const n=document,r=localStorage;export const copyTextToClipboard=n=>navigator.clipboard.writeText(n),releaseFocus=()=>{n.activeElement?.blur()};const t="keydown",i="pointerdown";export const setupMessageReceiverFromIFrame=()=>{window.addEventListener("message",r=>{if(r.origin===location.origin){const u=r.data;switch(u.action){case t:const r=new KeyboardEvent(t,{...u.eventArgs,...{bubbles:!0}});n.body.dispatchEvent(r);break;case i:const f=new MouseEvent(i,{bubbles:!0});n.body.dispatchEvent(f)}}},!1)};